#include "interface.h"
#include <thrust/device_ptr.h>
#include <thrust/sort.h>
#include <cuda_runtime.h>

void sort_vec_i32(const int* input, int* output, int n, int iters) {
  cudaError_t err;
  int* d_input;
  int* d_output;
  err = cudaMalloc((void**)&d_input, n * sizeof(int));
  if (err != cudaSuccess) return;
  err = cudaMalloc((void**)&d_output, n * sizeof(int));
  if (err != cudaSuccess) return;
  err = cudaMemcpy((void*)d_input, input, n * sizeof(int), cudaMemcpyHostToDevice);
  if (err != cudaSuccess) return;
  for (int iter = 0; iter < iters; ++iter) {
    thrust::device_ptr<int> d_output_ptr(d_output);
    thrust::copy(thrust::device_pointer_cast(d_input), thrust::device_pointer_cast(d_input) + n, d_output_ptr);
    thrust::sort(thrust::device, d_output_ptr, d_output_ptr + n);
  }
  err = cudaMemcpy(output, d_output, n * sizeof(int), cudaMemcpyDeviceToHost);
  if (err != cudaSuccess) return;
  cudaFree(d_input);
  cudaFree(d_output);
}
